// API Base URL - Django Backend
const API_BASE = window.location.origin;

// Generic fetch wrapper
async function apiFetch(endpoint, options = {}) {
  const url = API_BASE + endpoint;

  const response = await fetch(url, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...options.headers,
    },
  });

  if (!response.ok) {
    throw new Error('API Error: ' + response.status);
  }

  return response.json();
}

// Devices API
export const devicesApi = {
  list: () => apiFetch('/devices/api/list/'),

  save: (data) => apiFetch('/devices/api/save/', {
    method: 'POST',
    body: JSON.stringify(data),
  }),

  delete: (id) => apiFetch('/devices/api/delete/', {
    method: 'POST',
    body: JSON.stringify({ id }),
  }),

  dashboard: () => apiFetch('/devices/api/dashboard/'),

  runBackup: (deviceId) => apiFetch('/devices/api/backup/run/', {
    method: 'POST',
    body: JSON.stringify({ device_id: deviceId }),
  }),

  backups: (deviceId) => apiFetch('/devices/api/backup/list/?device_id=' + deviceId),
};

// Audit API
export const auditApi = {
  list: (filters = {}) => {
    const params = new URLSearchParams(filters).toString();
    return apiFetch('/devices/api/audit-logs/?' + params);
  },
};

export default { devicesApi, auditApi };
